{
 "level": "A2",
 "intro": "In this topic, you will learn <strong>Past Simple Passive</strong>: how to form affirmatives, negatives, and questions in the past passive.",
 "rules": [
 {
 "label": "Formula",
 "color": "emerald",
 "text": "<strong>was/were + V3</strong>:",
 "example": "The house was built in 1990."
 },
 {
 "label": "Denial",
 "color": "rose",
 "text": "<strong>was/were + not + V3</strong>:",
 "example": "The letter was not sent."
 },
 {
 "label": "Question",
 "color": "blue",
 "text": "<strong>Was/Were + S + V3?</strong>:",
 "example": "Was the house built in 1990?"
 }
 ]
}

{
 "title": "1. Choice of was/were",
 "intro": "The verb <strong>be</strong> in the past tense:",
 "items": [
 {
 "label": "I/He/She/It",
 "title": "was",
 "subtitle": "I was invited. The house was built."
 },
 {
 "label": "You/We/They",
 "title": "were",
 "subtitle": "You were told. They were arrested."
 },
 {
 "label": "Singular nouns",
 "title": "was",
 "subtitle": "The car was stolen."
 },
 {
 "label": "Plural nouns",
 "title": "were",
 "subtitle": "The thieves were caught."
 }
 ]
}

{
 "title": "2. Affirmative sentences",
 "sections": [
 {
 "label": "Structure",
 "color": "emerald",
 "description": "Order: <strong>Subject + was/were + V3 (+ by agent)</strong>",
 "examples": [
 {
 "en": "The house was built in 1990.",
 "ua": "The house was built in 1990."
 },
 {
 "en": "The thieves were caught yesterday.",
 "ua": "The thieves were caught yesterday."
 },
 {
 "en": "I was invited to the party.",
 "ua": "I was invited to the party."
 }
 ]
 },
 {
 "label": "When to use?",
 "color": "sky",
 "description": "For <strong>completed actions in the past</strong>:",
 "examples": [
 {
 "en": "America was discovered in 1492.",
 "ua": "America was discovered in 1492."
 },
 {
 "en": "The letter was sent last week.",
 "ua": "The letter was sent last week."
 },
 {
 "en": "The window was broken during the storm.",
 "ua": "The window was broken during the storm."
 }
 ]
 }
 ]
}

{
 "title": "3. Negative sentences",
 "sections": [
 {
 "label": "Structure",
 "color": "rose",
 "description": "Add <strong>not</strong> after was/were: <strong>Subject + was/were + not + V3</strong>",
 "examples": [
 {
 "en": "The email was not sent.",
 "ua": "The email was not sent."
 },
 {
 "en": "The documents were not signed.",
 "ua": "The documents were not signed."
 },
 {
 "en": "I was not informed about the meeting.",
 "ua": "I was not informed about the meeting."
 }
 ]
 },
 {
 "label": "Abbreviated forms",
 "color": "amber",
 "description": "<strong>wasn't / weren't</strong> is used colloquially:",
 "examples": [
 {
 "en": "The door wasn't locked.",
 "ua": "The door wasn't locked."
 },
 {
 "en": "The rooms weren't cleaned yesterday.",
 "ua": "The rooms weren't cleaned yesterday."
 }
 ]
 }
 ]
}

{
 "title": "4. Interrogative sentences",
 "sections": [
 {
 "label": "Yes/No question",
 "color": "blue",
 "description": "<strong>Was/Were</strong> comes out on top: <strong>Was/Were + Subject + V3?</strong>",
 "examples": [
 {
 "en": "Was the car repaired?",
 "ua": "Was the car repaired?"
 },
 {
 "en": "Were the documents signed?",
 "ua": "Were the documents signed?"
 },
 {
 "en": "Was she invited to the party?",
 "ua": "Was she invited to the party?"
 }
 ]
 },
 {
 "label": "Wh question",
 "color": "sky",
 "description": "<strong>Wh-word + was/were + Subject + V3?</strong>",
 "examples": [
 {
 "en": "When was the house built?",
 "ua": "When was the house built?"
 },
 {
 "en": "Where was the car found?",
 "ua": "Where was the car found?"
 },
 {
 "en": "Why were they arrested?",
 "ua": "Why were they arrested?"
 }
 ]
 },
 {
 "label": "Short answers",
 "color": "amber",
 "description": "Answers with <strong>Yes/No + was/were (not)</strong>:",
 "examples": [
 {
 "en": "Was the letter sent? — Yes, it was. / No, it wasn't.",
 "ua": "Was the letter sent? — Yes, it was. / No, it wasn't."
 },
 {
 "en": "Were they informed? — Yes, they were. / No, they weren't.",
 "ua": "Were they informed? — Yes, they were. / No, they weren't."
 }
 ]
 }
 ]
}

{
 "title": "5. Active vs Passive: Past Simple",
 "intro": "Comparison of active and passive in the past:",
 "rows": [
 {
 "en": "Active: Tom wrote the letter yesterday.",
 "ua": "Active: Tom wrote the letter yesterday.",
 "note": "→ Passive: The letter was written yesterday."
 },
 {
 "en": "Active: They built this house in 1990.",
 "ua": "Active: They built this house in 1990.",
 "note": "→ Passive: This house was built in 1990."
 },
 {
 "en": "Active: Someone stole my bike.",
 "ua": "Active: Someone stole my bike.",
 "note": "→ Passive: My bike was stolen."
 }
 ],
 "warning": "📌 Time markers (yesterday, last week, in 1990) remain!"
}

{
 "title": "6. Time markers for the Past Simple Passive",
 "sections": {
 "label": "Typical markers",
 "color": "emerald",
 "description": "Past Simple Passive is often used with <strong>past tense</strong> markers:",
 "examples": [
 {
 "en": "yesterday",
 "ua": "yesterday"
 },
 {
 "en": "last week/month/year",
 "ua": "last week/month/year"
 },
 {
 "en": "in 1990 / in the 19th century",
 "ua": "in 1990 / in the 19th century"
 },
 {
 "en": "ago (two days ago)",
 "ua": "ago (two days ago)"
 }
 ]
 }
}

{
 "title": "7. Typical mistakes",
 "items": [
 {
 "label": "Error 1",
 "color": "rose",
 "title": "The wrong choice was/were.",
 "wrong": "The documents was signed.",
 "right": "✅ The documents were signed."
 },
 {
 "label": "Error 2",
 "color": "amber",
 "title": "Using V2 instead of V3.",
 "wrong": "The house was builded in 1990.",
 "right": "✅ The house was built in 1990."
 },
 {
 "label": "Error 3",
 "color": "sky",
 "title": "Skip be in the questions.",
 "wrong": "The letter sent yesterday?",
 "right": "✅ Was the letter sent yesterday?"
 }
 ]
}

{
 "title": "Keep learning",
 "items": [
 {
 "label": "What is Passive Voice?",
 "current": false
 },
 {
 "label": "Form: be + V3",
 "current": false
 },
 {
 "label": "Present Simple Passive",
 "current": false
 },
 {
 "label": "Past Simple Passive",
 "current": true
 }
 ]
}
